// Author: Yash Kadav// Email: yashkadav52@gmail.compackage com.foodordering.krishnafoods.admin.activityimport android.Manifestimport android.content.pm.PackageManagerimport android.graphics.Colorimport android.net.Uriimport android.os.Bundleimport android.view.Viewimport android.widget.ArrayAdapterimport android.widget.Toastimport androidx.activity.OnBackPressedCallbackimport androidx.activity.result.ActivityResultLauncherimport androidx.activity.result.PickVisualMediaRequestimport androidx.activity.result.contract.ActivityResultContractsimport androidx.activity.viewModelsimport androidx.appcompat.app.AlertDialogimport androidx.appcompat.app.AppCompatActivityimport androidx.core.app.ActivityCompatimport androidx.core.content.ContextCompatimport androidx.core.view.ViewCompatimport androidx.core.view.WindowCompatimport androidx.core.view.WindowInsetsCompatimport androidx.core.view.isVisibleimport com.cloudinary.android.MediaManagerimport com.foodordering.krishnafoods.BuildConfigimport com.foodordering.krishnafoods.Rimport com.foodordering.krishnafoods.admin.util.ImageHelperimport com.foodordering.krishnafoods.admin.viewmodel.AddItemViewModelimport com.foodordering.krishnafoods.databinding.AdminActivityAddItemBindingclass AddItemActivity : AppCompatActivity() {    private lateinit var binding: AdminActivityAddItemBinding    private val viewModel: AddItemViewModel by viewModels()    // Image Handling    private var selectedImageUri: Uri? = null    private var cameraImageUri: Uri? = null    private lateinit var photoPickerLauncher: ActivityResultLauncher<PickVisualMediaRequest>    private lateinit var cameraLauncher: ActivityResultLauncher<Uri>    // Dropdown Data Lists    private val categoryList = mutableListOf<String>()    private val liquidList = mutableListOf<String>()    private val solidWeightList = mutableListOf<String>()    private val liquidVolumeList = mutableListOf<String>()    companion object {        private const val CAMERA_PERMISSION_CODE = 101        private var cloudinaryInitialized = false    }    override fun onCreate(savedInstanceState: Bundle?) {        super.onCreate(savedInstanceState)        binding = AdminActivityAddItemBinding.inflate(layoutInflater)        setContentView(binding.root)        setupUI()        initCloudinary()        setupLaunchers()        observeViewModel()        setupListeners()    }    private fun setupUI() {        supportActionBar?.hide()        WindowCompat.setDecorFitsSystemWindows(window, false)        window.statusBarColor = Color.TRANSPARENT        binding.AddFood.setNavigationOnClickListener { handleBackPress() }        ViewCompat.setOnApplyWindowInsetsListener(binding.AddFood) { v, insets ->            val systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars())            v.setPadding(v.paddingLeft, systemBars.top, v.paddingRight, v.paddingBottom)            insets        }        binding.lottieProgressBar.setAnimation(R.raw.loading_animation)        onBackPressedDispatcher.addCallback(this, object : OnBackPressedCallback(true) {            override fun handleOnBackPressed() {                handleBackPress()            }        })    }    private fun setupLaunchers() {        photoPickerLauncher = registerForActivityResult(ActivityResultContracts.PickVisualMedia()) { uri ->            uri?.let {                selectedImageUri = it                binding.ivFoodImages.setImageURI(it)            }        }        cameraLauncher = registerForActivityResult(ActivityResultContracts.TakePicture()) { success ->            if (success) {                cameraImageUri?.let {                    selectedImageUri = it                    binding.ivFoodImages.setImageURI(it)                }            }        }    }    private fun observeViewModel() {        // 1. Loading State        viewModel.isLoading.observe(this) { isLoading ->            binding.lottieProgressBar.visibility = if (isLoading) View.VISIBLE else View.GONE            if (isLoading) binding.lottieProgressBar.playAnimation() else binding.lottieProgressBar.cancelAnimation()            binding.btnAddFood.isEnabled = !isLoading            binding.btnAddFood.text = if (isLoading) getString(R.string.uploading_image) else getString(R.string.add_item)        }        // 2. Success/Error Messages        viewModel.statusMessage.observe(this) { result ->            result.onSuccess { msg ->                Toast.makeText(this, msg, Toast.LENGTH_SHORT).show()                finish()            }.onFailure { error ->                Toast.makeText(this, error.message, Toast.LENGTH_SHORT).show()            }        }        // 3. Dropdown Data        viewModel.categories.observe(this) {            categoryList.clear(); categoryList.addAll(it)            setupCategorySpinner()        }        viewModel.liquidCategories.observe(this) { liquidList.clear(); liquidList.addAll(it) }        viewModel.solidWeightOptions.observe(this) { solidWeightList.clear(); solidWeightList.addAll(it) }        viewModel.liquidVolumeOptions.observe(this) { liquidVolumeList.clear(); liquidVolumeList.addAll(it) }    }    private fun setupCategorySpinner() {        val adapter = ArrayAdapter(this, android.R.layout.simple_dropdown_item_1line, categoryList)        binding.spinnerCategory.setAdapter(adapter)        binding.spinnerCategory.setOnItemClickListener { _, _, position, _ ->            val isLiquid = liquidList.contains(categoryList[position])            setupWeightSpinner(isLiquid)        }    }    private fun setupWeightSpinner(isLiquid: Boolean) {        val options = if (isLiquid) liquidVolumeList else solidWeightList        val adapter = ArrayAdapter(this, android.R.layout.simple_dropdown_item_1line, options)        binding.spinnerWeight.setAdapter(adapter)        binding.spinnerWeight.text.clear() // Clear previous selection    }    private fun setupListeners() {        binding.ivFoodImages.setOnClickListener { selectImageSource() }        binding.btnAddFood.setOnClickListener {            viewModel.uploadFoodItem(                name = binding.etFoodName.text.toString().trim(),                origPrice = binding.etFoodPrice.text.toString().trim().toIntOrNull(),                offPrice = binding.etOfferedPrice.text.toString().trim().toIntOrNull(),                category = binding.spinnerCategory.text.toString(),                weight = binding.spinnerWeight.text.toString(),                imageUri = selectedImageUri            )        }    }    private fun selectImageSource() {        val options = arrayOf("Camera", "Gallery")        AlertDialog.Builder(this)            .setTitle(R.string.select_image_source)            .setItems(options) { _, choice ->                when (choice) {                    0 -> checkCameraPermission()                    1 -> photoPickerLauncher.launch(PickVisualMediaRequest(ActivityResultContracts.PickVisualMedia.ImageOnly))                }            }.show()    }    private fun checkCameraPermission() {        if (ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) == PackageManager.PERMISSION_GRANTED) {            launchCamera()        } else {            ActivityCompat.requestPermissions(this, arrayOf(Manifest.permission.CAMERA), CAMERA_PERMISSION_CODE)        }    }    private fun launchCamera() {        cameraImageUri = ImageHelper.createCameraUri(this)        cameraImageUri?.let { cameraLauncher.launch(it) } ?: Toast.makeText(this, "Error initializing camera", Toast.LENGTH_SHORT).show()    }    override fun onRequestPermissionsResult(requestCode: Int, permissions: Array<out String>, grantResults: IntArray) {        super.onRequestPermissionsResult(requestCode, permissions, grantResults)        if (requestCode == CAMERA_PERMISSION_CODE && grantResults.isNotEmpty() && grantResults[0] == PackageManager.PERMISSION_GRANTED) {            launchCamera()        }    }    private fun initCloudinary() {        if (!cloudinaryInitialized) {            val config = hashMapOf(                "cloud_name" to BuildConfig.CLOUDINARY_CLOUD_NAME,                "api_key" to BuildConfig.CLOUDINARY_API_KEY            )            try {                MediaManager.init(this, config)                cloudinaryInitialized = true            } catch (_: IllegalStateException) {                // Already initialized            }        }    }    private fun handleBackPress() {        if (binding.lottieProgressBar.isVisible) {            Toast.makeText(this, "Please wait for upload to finish", Toast.LENGTH_SHORT).show()        } else {            finish()        }    }}